## 3.  C stub implementation – **`pcapng_stubs.c`**

```c
/* ----------------------------------------------------------------------
   OCaml <-> C++ bridge for libpcapng.
   Compile this file with a C++ compiler (e.g. g++ -std=c++11) because it
   includes C++ headers and uses `new`/`delete`.
----------------------------------------------------------------------- */

#define CAML_NAME_SPACE        /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include "pcapng_wrapper.hpp"   /* our tiny wrapper header */

/* --------------------------------------------------------------------
   Helper macros for the custom block that stores a `caml_pcapng_reader *`.
--------------------------------------------------------------------- */
static void caml_pcapng_finalize(value v)
{
    caml_pcapng_reader *r = *(caml_pcapng_reader **)Data_custom_val(v);
    if (r) {
        delete r->reader;
        r->reader = NULL;
        delete r;
    }
}

/* No comparison needed – we never store the value in a map. */
static int caml_pcapng_compare(value v1, value v2) { return 0; }

static struct custom_operations caml_pcapng_ops = {
    "pcapng.capture",
    caml_pcapng_finalize,
    caml_pcapng_compare,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default
};

/* --------------------------------------------------------------------
   Allocate a new OCaml custom block that holds a freshly created
   `caml_pcapng_reader`.  The block is returned to OCaml.
--------------------------------------------------------------------- */
static value caml_pcapng_wrap_reader(PcapNgReader *reader)
{
    CAMLparam0();
    CAMLlocal1(block);

    caml_pcapng_reader *wrapper = new caml_pcapng_reader;
    wrapper->reader = reader;

    block = caml_alloc_custom(&caml_pcapng_ops,
                              sizeof(caml_pcapng_reader *),
                              0,   /* finaliser cost */
                              1);  /* finaliser cost */
    *(caml_pcapng_reader **)Data_custom_val(block) = wrapper;
    CAMLreturn(block);
}

/* --------------------------------------------------------------------
   open_file : string -> capture
--------------------------------------------------------------------- */
CAMLprim value caml_pcapng_open_file(value v_path)
{
    CAMLparam1(v_path);
    CAMLlocal1(res);
    const char *c_path = String_val(v_path);

    try {
        PcapNgReader *r = new PcapNgReader(std::string(c_path));
        res = caml_pcapng_wrap_reader(r);
    } catch (...) {
        translate_cpp_exception();            /* set static msg */
        caml_raise_with_string(*caml_named_value("Pcapng.Error"),
                               "Failed to open pcapng file");
    }
    CAMLreturn(res);
}

/* --------------------------------------------------------------------
   close : capture -> unit
--------------------------------------------------------------------- */
CAMLprim value caml_pcapng_close(value v_cap)
{
    CAMLparam1(v_cap);
    caml_pcapng_reader *wrap = *(caml_pcapng_reader **)Data_custom_val(v_cap);
    if (wrap && wrap->reader) {
        delete wrap->reader;
        wrap->reader = NULL;
    }
    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------------
   Helper: build an OCaml `frame` record from a native `Frame`.
--------------------------------------------------------------------- */
static value caml_pcapng_make_frame(const Frame &f)
{
    CAMLparam0();
    CAMLlocal3(v_ts_sec, v_ts_usec, v_data);

    v_ts_sec  = Val_int((int)f.ts_sec);
    v_ts_usec = Val_int((int)f.ts_usec);

    /* Allocate a `bytes` value and copy the payload */
    v_data = caml_alloc_string(f.length);
    memcpy(String_val(v_data), f.data, f.length);

    /* Construct the OCaml record (the order must match the .mli definition) */
    value v_frame = caml_alloc(3, 0);   /* 3 fields, tag 0 = record */
    Store_field(v_frame, 0, v_ts_sec);
    Store_field(v_frame, 1, v_ts_usec);
    Store_field(v_frame, 2, v_data);

    CAMLreturn(v_frame);
}

/* --------------------------------------------------------------------
   iter : capture -> (frame -> unit) -> unit
--------------------------------------------------------------------- */
CAMLprim value caml_pcapng_iter(value v_cap, value v_cb)
{
    CAMLparam2(v_cap, v_cb);
    caml_pcapng_reader *wrap = *(caml_pcapng_reader **)Data_custom_val(v_cap);
    if (!wrap || !wrap->reader) {
        caml_raise_with_string(*caml_named_value("Pcapng.Error"),
                               "iter on closed capture");
    }

    /* The callback must be kept alive across the C++ loop. */
    caml_register_global_root(&v_cb);

    try {
        Frame native_f;
        while (wrap->reader->next_frame(native_f)) {
            value v_frame = caml_pcapng_make_frame(native_f);
            /* Call the OCaml function with the frame. */
            caml_callback(v_cb, v_frame);
            /* If the OCaml function raises, caml_callback never returns;
               the exception propagates out of the loop. */
        }
    } catch (...) {
        caml_remove_global_root(&v_cb);
        translate_cpp_exception();
        caml_raise_with_string(*caml_named_value("Pcapng.Error"),
                               "C++ iterator raised an exception");
    }

    caml_remove_global_root(&v_cb);
    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------------
   to_list : capture -> frame list
   (convenient for tests; implemented in terms of iter)
--------------------------------------------------------------------- */
CAMLprim value caml_pcapng_to_list(value v_cap)
{
    CAMLparam1(v_cap);
    CAMLlocal3(v_cb, v_cons, v_acc);

    /* Build a closure that prepends each frame to an accumulator. */
    v_acc  = Val_int(0);  /* [] */
    v_cons = caml_alloc(2, 0);    /* :: constructor */
    Store_field(v_cons, 1, v_acc);   /* tail = [] initially */

    /* The closure is: fun f -> acc := f :: !acc */
    v_cb = caml_alloc_closure(1, 0);  /* 1 argument, 0 captured env */
    Store_field(v_cb, 0, v_cons);     /* captured env = cons cell */

    /* The generated closure code (written in C) */
    static value to_list_closure(value arg, value env)
    {
        CAMLparam2(arg, env);
        CAMLlocal1(new_cons);
        new_cons = caml_alloc(2, 0);            /* new :: old */
        Store_field(new_cons, 0, arg);          /* head = current frame */
        Store_field(new_cons, 1, Field(env, 1));/* tail = old list */
        Store_field(env, 1, new_cons);          /* update env */
        CAMLreturn(Val_unit);
    }

    /* Bind the C function to the closure */
    caml_register_named_value("Pcapng.to_list_closure", to_list_closure);
    caml_set_closure(v_cb, (void *)to_list_closure);

    /* Run the iterator */
    caml_pcapng_iter(v_cap, v_cb);

    /* The result list is stored in the captured env of the cons cell */
    CAMLreturn(Field(v_cons, 1));
}

/* --------------------------------------------------------------------
   Register the custom exception so that the stub can raise it.
--------------------------------------------------------------------- */
CAMLprim value caml_pcapng_register_exn(value unit)
{
    CAMLparam0();
    static const char *exn_name = "Pcapng.Error";
    caml_register_named_value(exn_name, caml_raise_failure);
    CAMLreturn(Val_unit);
}
```

### What the stub does, step by step

| OCaml function | What the stub does | Remarks |
|----------------|-------------------|---------|
| `open_file`    | `new PcapNgReader(path)` → custom block | Errors are caught, translated to `Pcapng.Error`. |
| `close`        | `delete reader` (if not already closed) | No‑op if already closed. |
| `iter cap cb`  | Registers `cb` as a global root, loops `next_frame`, builds an OCaml `frame` record for each native frame, calls `caml_callback(cb, frame)`. | The global root prevents the GC from moving the closure while the C++ loop runs. |
| `to_list`      | Builds a tiny closure that prepends each frame to a list, then calls `iter`. | Implemented purely for testing; not meant for huge captures. |
| `register_exn` | Registers the exception name `Pcapng.Error` so the stub can raise it. | Call once from the OCaml side (e.g. in a module initializer). |

